import type { ReactNode } from 'react';

import type { ChartUnit } from '../../../core/types/chart-unit.js';
import type { Timeseries } from '../../../core/types/timeseries.js';
import type { ProgrammaticZoomHandlers } from '../../../core/types/zoom.js';

export const CHART_VARIANT_OPTIONS = ['line', 'area', 'bar'] as const;
export type ChartVariant = (typeof CHART_VARIANT_OPTIONS)[number];
export type ChartVariantInternal = ChartVariant | 'band';
export const DEFAULT_VARIANT: ChartVariant = 'line';

export interface TimeseriesBandDataPoint {
  y0: number;
  y1: number;
  start: Date;
  end?: Date;
}

export interface TimeseriesBand extends Record<string, unknown> {
  datapoints: TimeseriesBandDataPoint[];
  name: string | string[];
  unit?: ChartUnit;
}

export interface TimeseriesChartLineProps {
  data: Timeseries;
}

export interface TimeseriesChartAreaProps {
  data: Timeseries;
}

export interface TimeseriesChartBarProps {
  data: Timeseries;
}

export interface TimeseriesChartBandProps {
  data: TimeseriesBand;
}

export type TimeseriesChartProps = {
  data?: Timeseries[];
  variant?: ChartVariant;
  children?: ReactNode;
} & Record<string, unknown>;

export interface TimeseriesChartRef extends ProgrammaticZoomHandlers {
  element: HTMLDivElement | null;
  getConfig: () => string;
  downloadData: () => void;
}
